import{_ as a,o as i,c as r,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Tableros de distribución","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/equipment/switchboards.md","filePath":"es/power-systems/equipment/switchboards.md"}'),o={name:"es/power-systems/equipment/switchboards.md"};function n(t,e,l,c,d,p){return i(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="tableros-de-distribucion" tabindex="-1">Tableros de distribución <a class="header-anchor" href="#tableros-de-distribucion" aria-label="Permalink to &quot;Tableros de distribución&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los tableros de distribución son conjuntos utilizados para distribuir energía en baja tensión dentro de instalaciones industriales y comerciales.</p><p>Sirven como puntos centrales de distribución donde la energía de entrada se divide en múltiples alimentadores de salida.</p><p>Los tableros de distribución típicamente operan a baja tensión y manejan altos niveles de corriente.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de los tableros de distribución es:</p><ul><li>Distribuir energía en baja tensión a diferentes áreas o sistemas</li><li>Proporcionar control y protección centralizados de múltiples alimentadores</li><li>Organizar la distribución eléctrica de manera estructurada y accesible</li><li>Permitir operación y mantenimiento seguros de los circuitos de energía</li></ul><p>Actúan como la interfaz principal entre el suministro de baja tensión de entrada y la distribución aguas abajo.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La energía ingresa al tablero de distribución desde un transformador o equipo de distribución aguas arriba.</p><p>Dentro del tablero, la energía se distribuye a través de:</p><ul><li>Interruptor automático o interruptor principal de entrada</li><li>Barras colectoras que transportan energía a través del conjunto</li><li>Interruptores automáticos de alimentadores que suministran los circuitos de salida</li></ul><p>Cada alimentador está protegido por su propio dispositivo, permitiendo aislar circuitos individuales sin afectar todo el sistema.</p><p>También pueden incluirse dispositivos de medición y monitoreo para rastrear corriente, voltaje y consumo de energía.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los tableros de distribución se utilizan en:</p><ul><li>Puntos principales de distribución en baja tensión en instalaciones industriales</li><li>Alimentación de paneles de subdistribución y centros de control de motores</li><li>Alimentación de grandes grupos de cargas como áreas de producción</li><li>Edificios comerciales y sistemas de infraestructura</li></ul><p>Típicamente se instalan cerca del transformador principal o del suministro de entrada.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Capacidad de corriente</strong><br> Debe manejar la demanda total de carga y la expansión futura</p></li><li><p><strong>Capacidad de cortocircuito</strong><br> El equipo debe soportar la corriente de falla disponible</p></li><li><p><strong>Número de alimentadores</strong><br> Debe permitir una distribución adecuada de cargas y capacidad de reserva</p></li><li><p><strong>Dispositivos de protección</strong><br> La selección de interruptores automáticos afecta la coordinación y la seguridad</p></li><li><p><strong>Distribución física</strong><br> La accesibilidad, la entrada de cables y el espacio para mantenimiento son importantes</p></li><li><p><strong>Normas y cumplimiento</strong><br> Debe cumplir con los requisitos eléctricos y de seguridad aplicables</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Los tableros de distribución manejan altas corrientes, requiriendo ventilación y espaciado adecuados</li><li>Un balance deficiente de cargas puede provocar sobrecalentamiento de barras colectoras y alimentadores</li><li>El etiquetado claro simplifica la operación y el diagnóstico</li><li>Incluir posiciones de alimentadores de reserva reduce el esfuerzo de modificación futura</li><li>El torque adecuado en las conexiones es crítico para evitar fallas</li></ul>',23)])])}const b=a(o,[["render",n]]);export{m as __pageData,b as default};
